sys_script_include.script:
var DecisionParser = Class.create();
DecisionParser.prototype = {
    _decision: "",
    _entries: [],

    DEFAULT_HELPER: function(questions, filter = DecisionParser.Filter.VALID, includeDefaultAnswer = false) {

        //  {
        //   "result": [ <-- take only this array
        //     {
        //       "defaultAnswer": true,
        var entries = questions.result;

        if (!includeDefaultAnswer) entries = entries.filter(e => e.defaultAnswer == false);

        entries = entries.map(function(e) {
            // The question has a 'answer.valid' property, but we do not use it,
            // it can be misleading in rare cases. Set valid to true for now.
            var obj = {
                "valid": true,
                "location": "",
                "message": ""
            };

            // Ex: "condition": "u_location=54^EQ",
            obj.location = e.condition == "" ? "" : e.condition.split("=")[1].split("^")[0].trim();

            // In rare cases the condition will be empty, making this entry invalid
            if (obj.location == "") {
                obj.valid = false;
                obj.message = "No location code";
            }

            // question.answer.answerElementValues.length will be > 0 if the
            // location is mapped to something. However, that reference could
            // be broken. We will check later, for now just capture the reference.
            if (e.answer.answerElementValues.length > 0) {

                // In rare cases we get a broken Reference, if the Reference
                // the user selected is deleted. In these cases the
                // answerElement array is populated but valid is false
                // and label is empty:
                //
                // 	"answerElementValues": [
                //   {
                //     "valid": false, <--
                //     "label": "", <--
                //     "answerElementName": "u_location",
                //     "type": "reference",
                //     "value": "25ab9a3b0a0a0bb300462c63ec6c1fb8",
                //   }
                // ],
                if (e.answer.answerElementValues[0].valid == false && e.answer.answerElementValues[0].label == "") {
                    // broken Reference
                    obj.valid = false;
                    obj.message = "No Location";
                } else {
                    // OK, good Reference
                    obj['reference'] = {
                        "label": e.answer.answerElementValues[0].label,
                        "value": e.answer.answerElementValues[0].value
                    };
                }
            }

            return obj;
        });

        // If the location was not mapped to anything, answer.answerElementValues
        // is an empty array, and we mark this invalid
        entries
            .filter(function(e) {
                return e.valid && !Object.hasOwn(e, 'reference');
            })
            .forEach(function(e) {
                e.valid = false;
                e.message = "No Location";
            });

        // If any entry has a blank location code, mark it invalid
        entries
            .filter(function(e) {
                return e.valid && e.location.length == 0;
            })
            .forEach(function(e) {
                e.valid = false;
                e.message = "no location";
            });

        // If any entry has a blank location, mark it invalid
        entries
            .filter(function(e) {
                return e.valid && e.location.length == 0;
            })
            .forEach(function(e) {
                e.valid = false;
                e.message = "no location";
            });

        // Check for duplicate loction codes, mark invalid
        // any entry having one of these. No return value.
        var locations = [];
        entries
            .filter(function(e) {
                return e.location.length > 0;
            })
            .forEach(function(e) {
                locations.push(e.location);
            });
        entries
            .filter(function(e) {
                return e.valid == true;
            })
            .forEach(function(e) {
                if (locations.indexOf(e.location) != locations.lastIndexOf(e.location)) {
                    e.valid = false;
                    e.message = "Duplicate location";
                }
            });

		// The filter argument is one of {Filter.VALID, Filter.INVALID, Filter.ALL},
		// and refers to our domain definition of valid, not the valid assigned
		// by the API
		if (filter == this.Filter.VALID) {
            entries = entries.filter(function(e) {
                return e.valid == true;
            });
        }
        if (filter == this.Filter.INVALID) {
            entries = entries.filter(function(e) {
                return e.valid == false;
            });
        }

        return entries;
    },

    Filter: {
        ALL: 0,
        VALID: 1,
        INVALID: 2
    },

    initialize: function(decisionTableName) {
        var gr_decision = new GlideRecord("sys_decision");
        gr_decision.addQuery("name", decisionTableName);
        gr_decision.setLimit(1);
        gr_decision.query();
        gr_decision.next();
        this._decision = gr_decision.getValue("sys_id");
    },

    getEntries: function(helper, filter = this.Filter.VALID, includeDefaultAnswer = false) {
        var dt = new sn_dt.DecisionTableAPI();
        var questions = dt.getQuestions(this._decision);
        return helper(questions, filter, includeDefaultAnswer);
    },

    getMap: function(helper, filter = this.Filter.VALID, includeDefaultAnswer = false) {
        var entries = this.getEntries(helper, filter, includeDefaultAnswer);

        // filter out entries with no location, we 
        // cannot match on them with any valid value
        entries = entries.filter(function(e) {
            return e.location.length > 0;
        });

        // reduce remaining entries to map. This may obfuscate
        // certain issues in the data such as duplicated location code.
        // For the clearest view of the data -> use getEntries().
        // For most efficient iteration over location codes --> use getMap().
        return entries.reduce((acc, item) => {
            acc[item.location] = {
                "valid": item.valid,
                "message": item.message
            };
            if (Object.hasOwn(item, "reference")) {
                acc[item.location]["reference"] = item["reference"];
            }
            return acc;
        }, {});
    },

    type: 'DecisionParser'
};
